const rows = $input.all();
if (rows.length === 0 || !rows[0].json.post_id) {
  return [{ json: { text: 'No recent LinkedIn posts found.', post_ids: [], ref_map: {} } }];
}

const posts = {};
const postIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const pId = data.post_id;
  if (!pId) return;

  postIds.add(pId);
  if (!posts[pId]) {
    posts[pId] = {
      content: data.post_content,
      url: data.post_url,
      published_at: data.post_published_at,
      likes_count: data.likes_count || 0,
      comments: []
    };
  }

  if (data.comment_id) {
    if (!posts[pId].comments.some(c => c.id === data.comment_id)) {
      posts[pId].comments.push({
        id: data.comment_id,
        author: data.comment_author,
        content: data.comment_content,
        published_at: data.comment_published_at
      });
    }
  }
});

const refMap = {};
let refCounter = 1;

let text = 'LinkedIn posts to analyze (each has an id number):\n\n';

Object.entries(posts).forEach(([pId, post]) => {
  const refId = refCounter++;
  const snippet = (post.content || '').substring(0, 40).replace(/\n/g, ' ') || 'LinkedIn Post';
  refMap[String(refId)] = { title: snippet, url: post.url || '' };

  text += `  id:${refId} | Published: ${post.published_at} | Likes: ${post.likes_count}\n`;
  text += `  Content: ${post.content || 'No content'}\n`;
  if (post.comments.length > 0) {
    text += `  Comments:\n`;
    post.comments.forEach(comment => {
      text += `    - by ${comment.author}: ${comment.content}\n`;
    });
  }
  text += '\n';
});

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

return [{ json: { text, post_ids: Array.from(postIds), ref_map: refMap, giusy_persona: persona } }];

const raw = $input.first().json.content || $input.first().json.response || '';
const refMap = $('Format Posts for LLM').first().json.ref_map || {};

let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    const cleanedStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(cleanedStr);
  } catch (err) {
    return [{ json: { response: raw } }];
  }
}

const greeting = parsed.greeting || '';
const signoff = parsed.signoff || '';
const performanceCritique = Array.isArray(parsed.performance_critique) ? parsed.performance_critique : [];
const communityActions = Array.isArray(parsed.community_engagement_actions) ? parsed.community_engagement_actions : [];
const strategicRecommendations = Array.isArray(parsed.strategic_recommendations) ? parsed.strategic_recommendations : [];

let msg = '';
if (greeting) msg += `${greeting}\n\n`;
msg += '📊 *LinkedIn Content Performance & Resonance Critique* 📊\n\n';

if (performanceCritique.length > 0) {
  msg += '*Post-by-Post Feedback*:\n';
  performanceCritique.forEach(c => {
    const ref = refMap[String(c.post_id)];
    const linkStr = ref && ref.url ? `<${ref.url}|${ref.title}...>` : `Post #${c.post_id}`;
    msg += `• *${linkStr}* | Resonance: *${c.resonance_score || 'N/A'}*\n`;
    msg += `  - *What worked*: ${c.positives || 'None'}\n`;
    msg += `  - *Critique*: ${c.critique || 'None'}\n`;
  });
  msg += '\n';
}

if (communityActions.length > 0) {
  msg += '*Community Engagement Plays*:\n';
  communityActions.forEach(action => {
    const ref = refMap[String(action.post_id)];
    const linkStr = ref && ref.url ? `<${ref.url}|Post>` : `Post #${action.post_id}`;
    msg += `• On *${linkStr}*, reply to *${action.commenter || 'Community'}*:\n`;
    msg += `  > "${action.actionable_reply}"\n`;
  });
  msg += '\n';
}

if (strategicRecommendations.length > 0) {
  msg += '*Strategic Writing Directives*:\n';
  strategicRecommendations.forEach(rec => {
    msg += `• ${rec}\n`;
  });
  msg += '\n';
}

if (signoff) msg += `${signoff}`;

return [{ json: { response: msg.trim() } }];
